   255→/*
   256→ * Gets a var with session scope
   257→ */
   258→int
   259→rewrite_session_var_get(
   260→		struct rewrite_info *info,
   261→		const void *cookie,
   262→		const char *name,
   263→		struct berval *value
   264→)
   265→{
   266→	struct rewrite_session *session;
   267→	struct rewrite_var *var;
   268→	int rc = REWRITE_SUCCESS;
   269→
   270→	assert( info != NULL );
   271→	assert( cookie != NULL );
   272→	assert( name != NULL );
   273→	assert( value != NULL );
   274→
   275→	value->bv_val = NULL;
   276→	value->bv_len = 0;
   277→	
   278→	if ( cookie == NULL ) {
   279→		return REWRITE_ERR;
   280→	}
   281→
   282→	session = rewrite_session_find( info, cookie );
   283→	if ( session == NULL ) {
   284→		return REWRITE_ERR;
   285→	}
   286→
   287→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   288→	ldap_pvt_thread_rdwr_rlock( &session->ls_vars_mutex );
   289→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   290→	
   291→	var = rewrite_var_find( session->ls_vars, name );
   292→	if ( var != NULL ) {
   293→		value->bv_val = strdup( var->lv_value.bv_val );
   294→		value->bv_len = var->lv_value.bv_len;
   295→	}
   296→
   297→	if ( var == NULL || value->bv_val == NULL ) {
   298→		rc = REWRITE_ERR;
   299→	}
   300→
   301→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   302→        ldap_pvt_thread_rdwr_runlock( &session->ls_vars_mutex );
   303→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   304→
   305→	rewrite_session_return( info, session );
   306→
   307→	return rc;
   308→}
   309→
   310→static void
   311→rewrite_session_clean( void *v_session )
   312→{
   313→	struct rewrite_session	*session = (struct rewrite_session *)v_session;
   314→
   315→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   316→	ldap_pvt_thread_rdwr_wlock( &session->ls_vars_mutex );
   317→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   318→
   319→	rewrite_var_delete( session->ls_vars );
   320→
   321→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   322→	ldap_pvt_thread_rdwr_wunlock( &session->ls_vars_mutex );
   323→	ldap_pvt_thread_rdwr_destroy( &session->ls_vars_mutex );
   324→	ldap_pvt_thread_mutex_unlock( &session->ls_mutex );
   325→	ldap_pvt_thread_mutex_destroy( &session->ls_mutex );
   326→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   327→}
   328→
   329→static void
   330→rewrite_session_free( void *v_session )
   331→{
   332→	struct rewrite_session	*session = (struct rewrite_session *)v_session;
   333→
   334→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   335→	ldap_pvt_thread_mutex_lock( &session->ls_mutex );
   336→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   337→	rewrite_session_clean( v_session );
   338→	free( v_session );
   339→}
   340→
   341→/*
   342→ * Deletes a session
   343→ */
   344→int
   345→rewrite_session_delete(
   346→		struct rewrite_info *info,
   347→		const void *cookie
   348→)
   349→{
   350→	struct rewrite_session *session, tmp = { 0 };
   351→
   352→	assert( info != NULL );
   353→	assert( cookie != NULL );
   354→
   355→	session = rewrite_session_find( info, cookie );
   356→
   357→	if ( session == NULL ) {
   358→		return REWRITE_SUCCESS;
   359→	}
   360→
   361→	if ( --session->ls_count > 0 ) {
   362→		rewrite_session_return( info, session );
   363→		return REWRITE_SUCCESS;
   364→	}
   365→
   366→	rewrite_session_clean( session );
   367→
   368→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   369→	ldap_pvt_thread_rdwr_wlock( &info->li_cookies_mutex );
   370→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   371→
   372→	assert( info->li_num_cookies > 0 );
   373→	info->li_num_cookies--;
   374→	
   375→	/*
   376→	 * There is nothing to delete in the return value
   377→	 */
   378→	tmp.ls_cookie = ( void * )cookie;
   379→	ldap_avl_delete( &info->li_cookies, ( caddr_t )&tmp, rewrite_cookie_cmp );
   380→
   381→	free( session );
   382→
   383→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   384→	ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   385→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   386→
   387→	return REWRITE_SUCCESS;
   388→}
   389→
   390→/*
   391→ * Destroys the cookie tree
   392→ */
   393→int
   394→rewrite_session_destroy(
   395→		struct rewrite_info *info
   396→)
   397→{
   398→	int count;
   399→
   400→	assert( info != NULL );
   401→	
   402→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   403→	ldap_pvt_thread_rdwr_wlock( &info->li_cookies_mutex );
   404→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   405→
   406→	/*
   407→	 * Should call per-session destruction routine ...
   408→	 */
   409→	
   410→	count = ldap_avl_free( info->li_cookies, rewrite_session_free );
   411→	info->li_cookies = NULL;
   412→
   413→#if 0
   414→	fprintf( stderr, "count = %d; num_cookies = %d\n", 
   415→			count, info->li_num_cookies );
   416→#endif
   417→	
   418→	assert( count == info->li_num_cookies );
   419→	info->li_num_cookies = 0;
   420→
   421→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   422→	ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   423→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   424→
   425→	return REWRITE_SUCCESS;
   426→}
